existing_ids = {b['id'] for b in books}
added = 0
for b in new_books:
    if b['id'] not in existing_ids:
        books.append(b)
        added += 1

with open('/root/books/webapp/books.json', 'w', encoding='utf-8') as f:
    json.dump(books, f, ensure_ascii=False, separators=(',', ':'))

print(f"Добавлено: {added} книг")
errors = []
for b in new_books:
    dlen = len(b['description'])
    if not (125 <= dlen <= 150):
        errors.append(f"DESC {b['id']} {b['title']}: {dlen}")
    for i, t in enumerate(b['thoughts']):
        total = len(t['title']) + len(t['example'])
        if not (600 <= total <= 800):
            errors.append(f"  {b['id']} thought {i}: {total} chars")

if errors:
    print("ОШИБКИ:")
    for e in errors: print(" ", e)
else:
    print("Все длины OK!")
